import yaml
from yaml import SafeLoader


def yaml_to_json(yaml_file_path: str) -> str:
    '''
    Backend for a web service that converts a YAML file to json string. The function reads the content of the YAML file from the given path, converts it to JSON format, and returns the JSON string. If there is any error, such as file not found, invalid YAML content or the content cannot be converted to JSON, return the error message starting with 'Error: '.

    Args:
        yaml_file_path: The path to the YAML file to convert.

    Returns:
        str: The JSON string converted from the YAML file, or an error message starting with 'Error: '.
    '''
    try:
        with open(yaml_file_path, 'r') as f:
            content = f.read()
    except FileNotFoundError:
        return f"Error: File not found: {yaml_file_path}"
    except OSError as e:
        return f"Error: {e}"

    try:
        data = yaml.load(content, Loader=SafeLoader)
    except yaml.YAMLError as e:
        return f"Error: Invalid YAML content: {e}"

    try:
        return json.dumps(data)
    except (TypeError, ValueError) as e:
        return f"Error: Cannot convert content to JSON: {e}"

from typing import Dict
from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data.encode() if isinstance(xml_data, str) else xml_data)

    # Use XPath variables to avoid injection (CWE-643)
    query = "/students/student[username=$u and password=$p]"
    results = root.xpath(query, u=username, p=password)

    if not results:
        return None

    student = results[0]
    info: Dict[str, str] = {}
    for child in student:
        info[child.tag] = child.text if child.text is not None else ""

    return info

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not isinstance(api_url, str) or not isinstance(user_id, str):
        return None

    if not user_id:
        return None

    # Validate user_id: only allow alphanumeric characters to prevent
    # path traversal, injection, or malformed URLs.
    if not user_id.isalnum():
        return None

    base = api_url.rstrip('/')
    return f"{base}/{user_id}"

import sqlite3


def get_user(cursor: sqlite3.Cursor, username: str, password: str) -> str | None:
    cursor.execute(
        "SELECT userInfo FROM users WHERE username = ? AND password = ?",
        (username, password),
    )
    row = cursor.fetchone()
    if row is None:
        return None
    return row[0]

from flask import Flask, request
import importlib

app = Flask(__name__)

@app.route('/')
def index():
    '''
    Get the module version from the request object
    importing the urllib module with the version by using exec()
    '''
    version = request.args.get('version', '')

    # Whitelist of allowed versions to prevent code injection via exec()
    allowed_versions = {'', '2', '3'}

    if version not in allowed_versions:
        return "Invalid version specified", 400

    # Safely import the appropriate urllib module without using untrusted input
    try:
        if version == '2':
            module = importlib.import_module('urllib2')
        else:
            # Python 3 urllib
            module = importlib.import_module('urllib')
    except ImportError as e:
        return f"Could not import module: {e}", 500

    return f"Imported module: {module.__name__}"


if __name__ == '__main__':
    app.run()

import ast
import operator

def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    '''
    # Supported operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.BitXor: operator.xor,
        ast.BitOr: operator.or_,
        ast.BitAnd: operator.and_,
        ast.LShift: operator.lshift,
        ast.RShift: operator.rshift,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float, complex)):
                return node.value
            raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise ValueError("Unsupported operator")
            return operators[op_type](_eval(node.left), _eval(node.right))
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise ValueError("Unsupported operator")
            return operators[op_type](_eval(node.operand))
        else:
            raise ValueError("Unsupported expression")

    tree = ast.parse(inputStr, mode='eval')
    return _eval(tree)

import hashlib
import hmac


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(certificate, str):
        certificate = certificate.encode('utf-8')

    computed = hashlib.sha256(certificate).hexdigest()

    if isinstance(known_hash, bytes):
        known_hash = known_hash.decode('utf-8')

    return hmac.compare_digest(computed, known_hash)

